var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐야, 저 사람이 누구길래 아저씨들이 죄다 조용해?","JPN":"なに？　あの人が喋り始めたら、おじさんたちみんな黙り込んだよ？","ENG":"Who is she? Why did all the old guys go quiet?","TWN":"什麼啊，那個人是誰，叔叔們怎麼都安靜了？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>전 세대</color> 백양궁의 기사. 메데이아 데이비스.","JPN":"<color=#ffd34c>先代</color>の白羊宮の騎士、メデイア・デイヴィス。","ENG":"The Knight of Aries from the <color=#ffd34c>previous generation</color>. Medea Davis.","TWN":"<color=#ffd34c>前世代</color>白羊宮的騎士。美狄亞·戴維斯。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"전임 기사단장과 함께 조디악 나이츠의 황금세대를 이끈 기사들 중 한 명입니다.","JPN":"前騎士団長と共にゾディアックナイツの黄金世代を率いた騎士の一人です。","ENG":"One of the knights who led the golden generation of the Zodiac Knights alongside the former captain.","TWN":"他是與前任騎士團長一起引領十二宮騎士黃金時代的騎士之一。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"비록 영광이 퇴색되고 그녀 역시 전선에서 물러났다고는 하나, 과거를 아는 이들에겐 여전히 선망의 대상이죠.","JPN":"たとえ栄光が色褪せ、彼女も戦線から身を引いているとはいえ、過去を知る者たちにとっては依然として憧れの人です。","ENG":"Though the luster of her glory has dimmed and she has retired from the front lines, she remains revered by those who remember her past.","TWN":"雖然榮耀已褪色，她也從前線退下，但對那些了解過去的人來說，她仍然是令人景仰的對象。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어… 유명한 사람인 것 같은데 난 왜 들은 기억이 없지?","JPN":"え……すごく有名な人みたいだけど、なんで名前を聞いたことないんだろう？","ENG":"Huh... sounds like she's famous, so why don't I remember hearing about her?","TWN":"呃……她好像很有名，但我怎麼沒聽說過呢？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그건 리브 경이 듣고 싶은 것만 듣고 살아서 그래요.","JPN":"それはリブ卿が聞きたいことしか聞いてないからです。","ENG":"Because you only pay attention to what you want, Dame Liv.","TWN":"那是因為莉芙只聽自己想聽的東西。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"품성은 몰라도 역대 기사단장직에 버금가는 실력을 지닌 줄리아 레온하르트.","JPN":"品性はともかく、歴代の騎士団長に匹敵する実力を持つジュリア・レオンハルト。","ENG":"Julia Leonhardt. Her character is debatable, but her skills were on par with any past Knight Captain.","TWN":"雖然品性不明，但茱莉亞·里恩哈特擁有接近歷代騎士團長的實力。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그녀가 어느 파벌에서도 단장직에 오르지 못했다는 점이 전 세대의 실력을 뒷받침하죠.","JPN":"彼女がどの派閥でも団長職に就けなかったことが、前の世代のすごさを証明しています。","ENG":"The fact that she never made captain despite that just shows how strong that generation was.","TWN":"她未能在任何派系中擔任團長職務，這證明了上一代的實力。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"다른 단원들의 실력 또한 명성이 자자했던 만큼, 기사단에서 그들의 입지는 상당합니다.","JPN":"他の団員たちの実力もまた評判に違わぬものであり、騎士団内での彼らの立場は相当なものです。","ENG":"Given the renown of their past prowess, the other members, too, hold considerable standing within the Order.","TWN":"其他成員的實力也同樣名聲顯赫，因此他們在騎士團中的地位相當高。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"하지만… 저분이 들고 있는 건 별의 무구 아닌가요?","JPN":"でも……あの方が持っているのは星の武具じゃないですか？","ENG":"But... isn't that a Star Armament she's carrying?","TWN":"但是… 那位拿著的不是星之武具嗎？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"전선에서 물러나셨다면, 어째서 무구를?","JPN":"戦線から身を引いているなら、どうしてまだ武具を？","ENG":"If she's retired, why would she still have it?","TWN":"既然已經退出前線，為什麼還要武裝自己？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"분파 소속이었던 저를 기사단에 들이고 양자리 기사직을 물려주신 게 누님이에요.","JPN":"分派所属だった私を騎士団に迎え入れ、牡羊座の騎士を譲ってくださったのがメデイアさんです。","ENG":"She was the one who brought me into the Order and passed down the Aries seat to me.","TWN":"是姊姊讓我這個曾經屬於分派的人加入了騎士團，並繼承了白羊座騎士的職位。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"다만, 제가 견습기사 신분이라 아직 무구는 누님에게 있죠.","JPN":"ただ、私はまだ見習い騎士なので、武具はメデイアさんが持っています。","ENG":"But since I'm still a trainee, the Armament is still in her possession.","TWN":"不過，我還是見習騎士，所以武器還在姊姊那裡。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어라. 한솔이 무구는 죽도가 아니었어?","JPN":"え？　イチロウの武具は竹刀じゃなかったの？","ENG":"Wait. I thought your Armament was just a bamboo sword?","TWN":"咦，楊瀚的武器不是竹刀嗎？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"그럴 리가 없잖아요! 애초에 평범한 죽도라고 몇 번이나 말했다고요!","JPN":"そんなわけないでしょう！　そもそも、普通の竹刀だって何度も言ったじゃないですか！","ENG":"Of course not! I've told you a dozen times it's just a regular training sword!","TWN":"怎麼可能！我已經說過好幾次這只是普通的竹刀了！"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"미안. 그런 컨셉인 줄.","JPN":"ごめん。そういう設定だと思ってた。","ENG":"Oops. Thought it was your thing.","TWN":"抱歉，我還以為是偽裝。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"오랜만이에요, 에스테로사 경. 이런 식의 재회라 아쉬울 따름이네요.","JPN":"お久しぶりです、エステロサ卿。再会がこのような形となってしまい、残念でなりません。","ENG":"It's been a while, Dame Esterosa. A shame we meet like this again.","TWN":"好久不見了，艾斯特洛索。以這樣的方式重逢，真是遺憾啊。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"예. 오랜만입니다, 메데이아 경.","JPN":"お久しぶりです。メデイア卿。","ENG":"Yes, it has. Dame Medea.","TWN":"是的。好久不見，美狄亞。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그런데… 가문의 목소리를 전하러 왔다는 것은?","JPN":"ところで……デイヴィス家の声を届けに来たというのは？","ENG":"But... when you say you're here to speak for your house?","TWN":"但是……你是來傳達家族的聲音的嗎？"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"문자 그대로의 의미예요.","JPN":"文字通りの意味ですわ。","ENG":"I mean exactly that.","TWN":"就是字面上的意思。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"데이비스 가문은, 현 단장인 에스테로사 경을 두둔합니다.","JPN":"デイヴィス家は、現団長であるエステロサ卿を支持します。","ENG":"House Davis supports the current captain, Dame Esterosa.","TWN":"戴維斯家族支持現任團長艾斯特洛索。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"안타깝지만 메데이아 경. 귀 가문에 관계없이 해당 안건은 가결된 것이나 다름없네.","JPN":"残念だがメデイア卿、デイヴィス家の意見は関係なく、この件は可決したも同然だ。","ENG":"Regrettably, Dame Medea. That matter has essentially already been decided, regardless of your house.","TWN":"很遺憾，美狄亞。無論你的家族如何，這項議案都已通過。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_NULL","text":{"KOREA":"이미 원로들의 뜻 또한 만장일치로…….","JPN":"すでに元老たちの意見も全員一致して……","ENG":"The Elder Council was unanimous...","TWN":"已經達成了元老們的一致意見……"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"레드시프트의 잠적 이후 원로원은 공석을 메우기 위한 인원을 급히 선별했죠.","JPN":"レッドシフトの失踪以来、元老院は空席を埋めるための人員を急いで選別しました。","ENG":"After the Red Shift vanished, the Elder Council rushed to fill the vacant seats.","TWN":"紅移失蹤後，元老院急忙挑選人員填補空缺。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"때문에 무구의 선택을 받았던 자만이 입회할 수 있었던 이전과 달리 현 원로원은 임시체제에 불과합니다.","JPN":"よって、武具に選ばれた者だけが入会できた昔とは違い、現在の元老院は臨時体制にすぎません。","ENG":"Unlike before, when only those chosen by a Star Armament could join, the current Council is merely provisional.","TWN":"因此，現任元老院只是一個臨時體制，不像以前只有被選中的人才能加入。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"만약 자격을 갖춘 이가 나타난다면, 당연히 그 자리를 승계해야겠지요.","JPN":"もし資格を持つ者が現れれば、当然その座を引き渡すべきでしょう。","ENG":"So if someone qualified appears, they should naturally take the seat.","TWN":"如果有合適的人出現，當然應該繼承那個位置。"},"stage":{"bg":"CHURCH_KNIGHT","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};